import{c as e,a7 as a,y as i,B as o}from"./chunks/framework.3cjvm90C.js";const f=JSON.parse('{"title":"CriticWorker","description":"解析veRL中基于FSDP的Critic Worker模块的设计与实现","frontmatter":{"title":"CriticWorker","description":"解析veRL中基于FSDP的Critic Worker模块的设计与实现"},"headers":[],"relativePath":"rlhf/infra/verl/fsdp_critic_worker.md","filePath":"rlhf/infra/verl/fsdp_critic_worker.md","lastUpdated":1782448598000}'),s={name:"rlhf/infra/verl/fsdp_critic_worker.md"};function l(d,r,p,t,h,c){return a(),i("div",null,[...r[0]||(r[0]=[o('<h1 id="criticworker" tabindex="-1">CriticWorker <a class="header-anchor" href="#criticworker" aria-label="Permalink to “CriticWorker”">​</a></h1><h2 id="整体概述" tabindex="-1">整体概述 <a class="header-anchor" href="#整体概述" aria-label="Permalink to “整体概述”">​</a></h2><p><code>CriticWorker</code> 是基于 FSDP （Fully Sharded Data Parallel）的价值函数 Worker，负责在 PPO 训练中估计状态价值并更新价值网络。 fsdp_workers.py:915-918 它继承自 <code>Worker</code> 和 <code>DistProfilerExtension</code>，支持分布式训练和性能分析。</p><h2 id="类初始化和配置" tabindex="-1">类初始化和配置 <a class="header-anchor" href="#类初始化和配置" aria-label="Permalink to “类初始化和配置”">​</a></h2><h3 id="构造函数核心逻辑-fsdp-workers-py-916-925" tabindex="-1">构造函数核心逻辑 fsdp_workers.py:916-925 <a class="header-anchor" href="#构造函数核心逻辑-fsdp-workers-py-916-925" aria-label="Permalink to “构造函数核心逻辑 fsdp_workers.py:916-925”">​</a></h3><p>构造函数首先初始化分布式环境，如果 PyTorch 分布式未初始化，会自动设置 NCCL 后端的进程组。</p><h3 id="设备网格和序列并行配置-fsdp-workers-py-927-942" tabindex="-1">设备网格和序列并行配置 fsdp_workers.py:927-942 <a class="header-anchor" href="#设备网格和序列并行配置-fsdp-workers-py-927-942" aria-label="Permalink to “设备网格和序列并行配置 fsdp_workers.py:927-942”">​</a></h3><p>代码构建了两种设备网格：</p><ul><li><strong>FSDP 设备网格</strong>：用于参数分片</li><li><strong>Ulysses 设备网格</strong>：用于序列并行，支持长序列处理</li></ul><h3 id="批次大小标准化-fsdp-workers-py-948-970" tabindex="-1">批次大小标准化 fsdp_workers.py:948-970 <a class="header-anchor" href="#批次大小标准化-fsdp-workers-py-948-970" aria-label="Permalink to “批次大小标准化 fsdp_workers.py:948-970”">​</a></h3><p>这段代码对训练批次大小进行标准化处理：</p><ul><li>根据 rollout 数量调整 mini batch size</li><li>按设备数量和序列并行大小缩放</li><li>确保 micro batch size 能被 mini batch size 整除</li></ul><h2 id="模型构建核心方法" tabindex="-1">模型构建核心方法 <a class="header-anchor" href="#模型构建核心方法" aria-label="Permalink to “模型构建核心方法”">​</a></h2><h3 id="build-critic-model-optimizer-方法-fsdp-workers-py-972-1172" tabindex="-1">_build_critic_model_optimizer 方法 fsdp_workers.py:972-1172 <a class="header-anchor" href="#build-critic-model-optimizer-方法-fsdp-workers-py-972-1172" aria-label="Permalink to “_build_critic_model_optimizer 方法 fsdp_workers.py:972-1172”">​</a></h3><p>这是价值模型构建的核心方法，包含以下关键步骤：</p><h4 id="_1-分词器和处理器初始化-fsdp-workers-py-985-987" tabindex="-1">1. 分词器和处理器初始化 fsdp_workers.py:985-987 <a class="header-anchor" href="#_1-分词器和处理器初始化-fsdp-workers-py-985-987" aria-label="Permalink to “1. 分词器和处理器初始化 fsdp_workers.py:985-987”">​</a></h4><h4 id="_2-模型配置和特殊适配-fsdp-workers-py-1009-1017" tabindex="-1">2. 模型配置和特殊适配 fsdp_workers.py:1009-1017 <a class="header-anchor" href="#_2-模型配置和特殊适配-fsdp-workers-py-1009-1017" aria-label="Permalink to “2. 模型配置和特殊适配 fsdp_workers.py:1009-1017”">​</a></h4><p>关键配置包括：</p><ul><li>设置 <code>num_labels = 1</code> 用于价值函数输出</li><li>为 kimi-vl 等特殊模型设置专用配置</li></ul><h4 id="_3-dropout-配置优化-fsdp-workers-py-1025-1027" tabindex="-1">3. Dropout 配置优化 fsdp_workers.py:1025-1027 <a class="header-anchor" href="#_3-dropout-配置优化-fsdp-workers-py-1025-1027" aria-label="Permalink to “3. Dropout 配置优化 fsdp_workers.py:1025-1027”">​</a></h4><p>禁用各种 dropout 以确保价值函数训练的稳定性。</p><h4 id="_4-价值头模型加载-fsdp-workers-py-1029-1034" tabindex="-1">4. 价值头模型加载 fsdp_workers.py:1029-1034 <a class="header-anchor" href="#_4-价值头模型加载-fsdp-workers-py-1029-1034" aria-label="Permalink to “4. 价值头模型加载 fsdp_workers.py:1029-1034”">​</a></h4><p>使用 <code>load_valuehead_model</code> 加载带有价值头的模型。</p><h4 id="_5-fsdp-包装策略-fsdp-workers-py-1093-1128" tabindex="-1">5. FSDP 包装策略 fsdp_workers.py:1093-1128 <a class="header-anchor" href="#_5-fsdp-包装策略-fsdp-workers-py-1093-1128" aria-label="Permalink to “5. FSDP 包装策略 fsdp_workers.py:1093-1128”">​</a></h4><p>支持两种 FSDP 策略：</p><ul><li><strong>FSDP v1</strong>：传统的 FSDP 包装</li><li><strong>FSDP v2</strong>：新版本的 fully_shard API</li></ul><h4 id="_6-优化器和学习率调度器-fsdp-workers-py-1136-1171" tabindex="-1">6. 优化器和学习率调度器 fsdp_workers.py:1136-1171 <a class="header-anchor" href="#_6-优化器和学习率调度器-fsdp-workers-py-1136-1171" aria-label="Permalink to “6. 优化器和学习率调度器 fsdp_workers.py:1136-1171”">​</a></h4><p>配置 AdamW 优化器和学习率调度器（支持 constant 和 cosine 两种预热策略）。</p><h2 id="核心训练方法" tabindex="-1">核心训练方法 <a class="header-anchor" href="#核心训练方法" aria-label="Permalink to “核心训练方法”">​</a></h2><h3 id="init-model-方法-fsdp-workers-py-1174-1203" tabindex="-1">init_model 方法 fsdp_workers.py:1174-1203 <a class="header-anchor" href="#init-model-方法-fsdp-workers-py-1174-1203" aria-label="Permalink to “init_model 方法 fsdp_workers.py:1174-1203”">​</a></h3><p>模型初始化入口点，使用 <code>@register(dispatch_mode=Dispatch.ONE_TO_ALL)</code> 装饰器确保所有 Worker 同步初始化。</p><h3 id="compute-values-方法-fsdp-workers-py-1205-1227" tabindex="-1">compute_values 方法 fsdp_workers.py:1205-1227 <a class="header-anchor" href="#compute-values-方法-fsdp-workers-py-1205-1227" aria-label="Permalink to “compute_values 方法 fsdp_workers.py:1205-1227”">​</a></h3><p>价值计算的核心方法：</p><ol><li>将数据移动到 GPU</li><li>处理参数卸载（如果启用）</li><li>使用 Ulysses 分片管理器处理序列并行</li><li>调用 critic 的 <code>compute_values</code> 方法</li><li>返回计算结果并移回 CPU</li></ol><h3 id="update-critic-方法-fsdp-workers-py-1229-1264" tabindex="-1">update_critic 方法 fsdp_workers.py:1229-1264 <a class="header-anchor" href="#update-critic-方法-fsdp-workers-py-1229-1264" aria-label="Permalink to “update_critic 方法 fsdp_workers.py:1229-1264”">​</a></h3><p>价值函数更新的核心方法：</p><ol><li>数据预处理和设备管理</li><li>执行价值函数更新训练</li><li>计算性能指标（MFU、内存使用等）</li><li>更新学习率调度器</li><li>返回训练指标</li></ol><h2 id="检查点管理" tabindex="-1">检查点管理 <a class="header-anchor" href="#检查点管理" aria-label="Permalink to “检查点管理”">​</a></h2><h3 id="保存和加载检查点-fsdp-workers-py-1266-1297" tabindex="-1">保存和加载检查点 fsdp_workers.py:1266-1297 <a class="header-anchor" href="#保存和加载检查点-fsdp-workers-py-1266-1297" aria-label="Permalink to “保存和加载检查点 fsdp_workers.py:1266-1297”">​</a></h3><p>支持分布式检查点的保存和加载，处理参数卸载的同步问题。</p><h2 id="技术要点" tabindex="-1">技术要点 <a class="header-anchor" href="#技术要点" aria-label="Permalink to “技术要点”">​</a></h2><h3 id="_1-hybridflow-架构集成" tabindex="-1">1. HybridFlow 架构集成 <a class="header-anchor" href="#_1-hybridflow-架构集成" aria-label="Permalink to “1. HybridFlow 架构集成”">​</a></h3><p>所有核心方法都使用 <code>@register</code> 装饰器，支持不同的分发模式：</p><ul><li><code>Dispatch.ONE_TO_ALL</code>：广播到所有 Worker</li><li><code>Dispatch.DP_COMPUTE_PROTO</code>：数据并行计算和收集</li></ul><h3 id="_2-内存优化策略" tabindex="-1">2. 内存优化策略 <a class="header-anchor" href="#_2-内存优化策略" aria-label="Permalink to “2. 内存优化策略”">​</a></h3><ul><li><strong>参数卸载</strong>：支持将 FSDP 参数卸载到 CPU</li><li><strong>优化器卸载</strong>：支持将优化器状态卸载到 CPU</li><li><strong>激活卸载</strong>：可选的激活检查点功能</li></ul><h3 id="_3-分布式训练支持" tabindex="-1">3. 分布式训练支持 <a class="header-anchor" href="#_3-分布式训练支持" aria-label="Permalink to “3. 分布式训练支持”">​</a></h3><ul><li><strong>FSDP 集成</strong>：使用 PyTorch FSDP 进行参数分片</li><li><strong>序列并行</strong>：通过 Ulysses 支持长序列处理</li><li><strong>混合精度</strong>：支持 bfloat16 参数和 fp32 梯度</li></ul><h3 id="_4-性能监控" tabindex="-1">4. 性能监控 <a class="header-anchor" href="#_4-性能监控" aria-label="Permalink to “4. 性能监控”">​</a></h3><p>集成了 FLOPS 计算器和内存使用监控，提供详细的训练性能指标。</p><h2 id="潜在改进建议" tabindex="-1">潜在改进建议 <a class="header-anchor" href="#潜在改进建议" aria-label="Permalink to “潜在改进建议”">​</a></h2><ol><li><strong>错误处理增强</strong>：可以添加更详细的异常处理和恢复机制</li><li><strong>配置验证</strong>：在初始化时验证配置参数的一致性</li><li><strong>动态批次大小</strong>：考虑支持动态调整批次大小以优化内存使用</li><li><strong>梯度累积优化</strong>：可以优化梯度累积策略以提高训练效率</li></ol><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to “Notes”">​</a></h2><p><code>CriticWorker</code> 是 verl 框架中价值函数训练的核心实现，与 <code>ActorRolloutRefWorker</code> 配合完成完整的 PPO 训练流程。它通过 FSDP 实现高效的分布式训练，支持大规模模型的价值函数学习。该类在 PPO 训练中负责估计状态价值，为优势函数计算提供基础。</p>',54)])])}const k=e(s,[["render",l]]);export{f as __pageData,k as default};
